#include <iostream>
using namespace std;

int main() {
    unsigned int positiveOnly = 4000000000U; // can't be negative
    long int bigNumber = 1000000000L;
    short int smallNumber = 32767;
    unsigned char byte = 255;

    cout << "unsigned int: " << positiveOnly << endl;
    cout << "long int: " << bigNumber << endl;
    cout << "short int: " << smallNumber << endl;
    cout << "unsigned char: " << (int)byte << endl;  // cast to int to see numeric

    // long long (C++11)
    long long veryBig = 9223372036854775807LL;
    cout << "long long: " << veryBig << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    string greeting = "Hello";
    string name = "Alice";

    // Concatenation
    string message = greeting + ", " + name + "!";
    cout << message << endl;

    // Length
    cout << "Length of message: " << message.length() << endl;

    // Access characters
    cout << "First character: " << message[0] << endl;

    // Input with spaces (use getline)
    string fullName;
    cout << "Enter your full name: ";
    getline(cin, fullName);
    cout << "Hello, " << fullName << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    cout << "Size of char: " << sizeof(char) << " byte(s)" << endl;
    cout << "Size of int: " << sizeof(int) << " bytes" << endl;
    cout << "Size of float: " << sizeof(float) << " bytes" << endl;
    cout << "Size of double: " << sizeof(double) << " bytes" << endl;
    cout << "Size of bool: " << sizeof(bool) << " byte(s)" << endl;

    int arr[10];
    cout << "Size of array of 10 ints: " << sizeof(arr) << " bytes" << endl;
    cout << "Number of elements: " << sizeof(arr) / sizeof(arr[0]) << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    const double PI = 3.1415926535;
    const int DAYS_IN_WEEK = 7;
    // PI = 3.14; // ERROR: cannot modify constant

    cout << "PI = " << PI << endl;
    cout << "Days in week = " << DAYS_IN_WEEK << endl;

    // Literal examples
    int decimal = 42;      // decimal literal
    int octal = 052;       // octal (starts with 0) = 42 decimal
    int hex = 0x2A;        // hexadecimal (starts with 0x) = 42
    unsigned int u = 42U;  // unsigned literal
    long l = 42L;          // long literal
    float f = 3.14f;       // float literal
    double d = 3.14;       // double literal
    char c = 'A';          // character literal
    string s = "Hello";    // string literal

    cout << "Decimal: " << decimal << ", Octal: " << octal << ", Hex: " << hex << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Implicit conversion
    int a = 3.14;   // double to int -> truncates to 3
    double b = 5;   // int to double -> 5.0

    cout << "Implicit: int from double = " << a << endl;
    cout << "Implicit: double from int = " << b << endl;

    // C-style cast
    double pi = 3.14159;
    int piInt = (int)pi;
    cout << "C-style cast: " << piInt << endl;

    // static_cast (preferred in C++)
    double price = 9.99;
    int dollars = static_cast<int>(price);
    cout << "static_cast: " << dollars << endl;

    // Converting between numeric and char
    int ascii = 65;
    char letter = static_cast<char>(ascii);
    cout << "ASCII 65 is char: " << letter << endl;

    // Beware of overflow
    int big = 1000000;
    short small = static_cast<short>(big);  // may overflow
    cout << "Overflow example: " << small << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    auto x = 42;           // int
    auto y = 3.14;         // double
    auto z = 'A';          // char
    auto s = string("Hello"); // std::string
    auto result = x + y;   // double (int + double)

    cout << "x type: int, value = " << x << endl;
    cout << "y type: double, value = " << y << endl;
    cout << "z type: char, value = " << z << endl;
    cout << "s type: string, value = " << s << endl;
    cout << "result type: double, value = " << result << endl;

    return 0;
}
